from argparse import ArgumentParser
from confluent_kafka.admin import AdminClient, NewTopic

def create_topic(args):
    admin_client = AdminClient({'bootstrap.servers': args.broker})
    topic = NewTopic(name=args.topic_name, num_partitions=args.num_partitions, replication_factor=args.replication_factor)
    # Create topics
    try:
        admin_client.create_topics([topic])
    except Exception as e:
        print(f"Failed to create topic {args.topic_name}: {str(e)}")
        return
    print(f"Topic {args.topic_name} created successfully.")

def main():
    parser = ArgumentParser()
    parser.add_argument("--broker", help="Bootstrap broker URLs (comma separated)", required=True)
    parser.add_argument("--topic-name", help="Name of the topic to create", required=True)
    parser.add_argument("--num-partitions", type=int, default=1, help="Number of partitions for the topic")
    parser.add_argument("--replication-factor", type=int, default=1, help="Replication factor for the topic")

    args = parser.parse_args()
    
    create_topic(args)

if __name__ == "__main__":
    main()